insert into public.customers (
  id, customer_guid, customer_name, customer_id, source_mode, active, send, department, accounting_key, payment_terms_days, phone, mobile, emails, contact_person, address, city, zip, country, bank_name, bank_branch, bank_account, remarks, income_amount, payment_amount, balance_amount, creation_date, last_update_date, customer_domain, bank_details_updated_sent, synced_at, raw_payload
)
select
  coalesce(nullif(payload->>'customer_guid',''), nullif(payload->>'customer_id',''), payload->>'customer_name') as id, payload->>'customer_guid' as customer_guid, payload->>'customer_name' as customer_name, payload->>'customer_id' as customer_id, payload->>'source_mode' as source_mode, false as active, case when payload ? 'send' then (payload->>'send')::boolean else null end as send, payload->>'department' as department, payload->>'accounting_key' as accounting_key, case when payload->>'payment_terms_days' = '' then null else (payload->>'payment_terms_days')::integer end as payment_terms_days, payload->>'phone' as phone, payload->>'mobile' as mobile, coalesce(payload->'emails','[]'::jsonb) as emails, payload->>'contact_person' as contact_person, payload->>'address' as address, payload->>'city' as city, payload->>'zip' as zip, payload->>'country' as country, payload->>'bank_name' as bank_name, payload->>'bank_branch' as bank_branch, payload->>'bank_account' as bank_account, payload->>'remarks' as remarks, case when payload->>'income_amount' = '' then null else (payload->>'income_amount')::numeric end as income_amount, case when payload->>'payment_amount' = '' then null else (payload->>'payment_amount')::numeric end as payment_amount, case when payload->>'balance_amount' = '' then null else (payload->>'balance_amount')::numeric end as balance_amount, payload->>'creation_date' as creation_date, payload->>'last_update_date' as last_update_date, payload->>'customer_domain' as customer_domain, case when payload ? 'bank_details_updated_sent' then (payload->>'bank_details_updated_sent')::boolean else null end as bank_details_updated_sent, case when payload->>'synced_at' = '' then null else (payload->>'synced_at')::timestamptz end as synced_at, payload as raw_payload
from source
on conflict (id) do update
set customer_guid = excluded.customer_guid, customer_name = excluded.customer_name, customer_id = excluded.customer_id, source_mode = excluded.source_mode, active = excluded.active, send = excluded.send, department = excluded.department, accounting_key = excluded.accounting_key, payment_terms_days = excluded.payment_terms_days, phone = excluded.phone, mobile = excluded.mobile, emails = excluded.emails, contact_person = excluded.contact_person, address = excluded.address, city = excluded.city, zip = excluded.zip, country = excluded.country, bank_name = excluded.bank_name, bank_branch = excluded.bank_branch, bank_account = excluded.bank_account, remarks = excluded.remarks, income_amount = excluded.income_amount, payment_amount = excluded.payment_amount, balance_amount = excluded.balance_amount, creation_date = excluded.creation_date, last_update_date = excluded.last_update_date, customer_domain = excluded.customer_domain, bank_details_updated_sent = excluded.bank_details_updated_sent, synced_at = excluded.synced_at, raw_payload = excluded.raw_payload;